div.script:
const canvas = document.getElementById('net');
const ctx = canvas.getContext('2d');
const banner = canvas.parentElement;

function resize() {
  canvas.width = banner.offsetWidth;
  canvas.height = banner.offsetHeight;
}
resize();
window.addEventListener('resize', resize);

const COLORS = {
  nodePrimary:  'rgba(59,130,246,',
  nodeAccent:   'rgba(232,131,74,',
  nodeDim:      'rgba(100,140,200,',
  edgePrimary:  'rgba(59,130,246,',
  edgeAccent:   'rgba(232,131,74,',
};

const NODE_COUNT = 38;
const CONNECT_DIST = 180;
const EDGE_FADE_DIST = 140;

class Node {
  constructor(i) {
    this.bx = Math.random();
    this.by = Math.random();
    this.r1  = 30 + Math.random() * 90;
    this.r2  = 15 + Math.random() * 50;
    this.s1  = (Math.random() * 0.0004 + 0.0001) * (Math.random() < 0.5 ? 1 : -1);
    this.s2  = (Math.random() * 0.0007 + 0.0002) * (Math.random() < 0.5 ? 1 : -1);
    this.a1  = Math.random() * Math.PI * 2;
    this.a2  = Math.random() * Math.PI * 2;
    this.dx  = (Math.random() - 0.5) * 0.04;
    this.dy  = (Math.random() - 0.5) * 0.04;
    this.isAccent = (i % 9 === 0);
    this.size = this.isAccent ? 2.5 : (1.2 + Math.random() * 1.6);
    this.pulse = Math.random() * Math.PI * 2;
    this.pulseSpeed = 0.008 + Math.random() * 0.012;
    this.x = 0; this.y = 0;
  }

  update(t) {
    this.a1 += this.s1 * t;
    this.a2 += this.s2 * t;
    this.bx = ((this.bx + this.dx * 0.0005) + 1) % 1;
    this.by = ((this.by + this.dy * 0.0005) + 1) % 1;
    this.pulse += this.pulseSpeed;
    const W = canvas.width, H = canvas.height;
    const xBase = W * (0.52 + this.bx * 0.48);
    const yBase = H * (0.05 + this.by * 0.90);
    this.x = xBase + Math.cos(this.a1) * this.r1 + Math.cos(this.a2) * this.r2;
    this.y = yBase + Math.sin(this.a1) * this.r1 * 0.6 + Math.sin(this.a2) * this.r2 * 0.7;
  }

  draw() {
    const p = 0.7 + 0.3 * Math.sin(this.pulse);
    const col = this.isAccent ? COLORS.nodeAccent : COLORS.nodePrimary;
    const r = this.size * p;
    const g = ctx.createRadialGradient(this.x, this.y, 0, this.x, this.y, r * 4);
    g.addColorStop(0, col + '0.35)');
    g.addColorStop(1, col + '0)');
    ctx.beginPath();
    ctx.arc(this.x, this.y, r * 4, 0, Math.PI * 2);
    ctx.fillStyle = g;
    ctx.fill();
    ctx.beginPath();
    ctx.arc(this.x, this.y, r, 0, Math.PI * 2);
    ctx.fillStyle = col + (this.isAccent ? '0.9)' : '0.8)');
    ctx.fill();
  }
}

const nodes = Array.from({length: NODE_COUNT}, (_, i) => new Node(i));
let last = performance.now();

function draw(now) {
  const dt = now - last;
  last = now;
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  nodes.forEach(n => n.update(dt));
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const a = nodes[i], b = nodes[j];
      const dx = a.x - b.x, dy = a.y - b.y;
      const dist = Math.sqrt(dx*dx + dy*dy);
      if (dist > CONNECT_DIST) continue;
      const alpha = Math.pow(1 - dist / CONNECT_DIST, 1.6) * 0.55;
      const isHot = a.isAccent || b.isAccent;
      const col = isHot ? COLORS.edgeAccent : COLORS.edgePrimary;
      const grad = ctx.createLinearGradient(a.x, a.y, b.x, b.y);
      grad.addColorStop(0, col + alpha + ')');
      grad.addColorStop(0.5, col + (alpha * 1.3) + ')');
      grad.addColorStop(1, col + alpha + ')');
      ctx.beginPath();
      ctx.moveTo(a.x, a.y);
      ctx.lineTo(b.x, b.y);
      ctx.strokeStyle = grad;
      ctx.lineWidth = isHot ? 0.8 : 0.5;
      ctx.stroke();
    }
  }
  nodes.forEach(n => n.draw());
  requestAnimationFrame(draw);
}

requestAnimationFrame(draw);
